    , BUYER_ADDRESS
    , DEST_COUNTRY
    , LOADING_PORT
    , GOODS_LOC
    , EXCHANGE_RATE
    , CURRENCY_CODE
    , PAY_AMOUNT
    , FREIGHT_AMT
    , INSURANCE_AMT
    , CARGO_MGMT_NO
    , BONDED_REP_NAME
    , CARRIER_NAME
    , VESSEL_NAME
    , LOADING_LOC
    , CONT_NO
    , HS_CODE
    , ITEM_NAME_DECLARED
