) VALUES (
      SEQ_EXPORT_LOG_ID.NEXTVAL
    , #{actionType}
    , SYSDATE
    , #{workerId}
    , #{exportId}
    , #{memId}
    , #{exporterName}
    , #{repName}
    , #{bizRegNo}
    , #{buyerIdNo}
    , #{customsId}
    , #{buyerName}
    , #{buyerAddress}
    , #{destCountry}
    , #{loadingPort}
    , #{goodsLoc}
    , #{exchangeRate}
    , #{currencyCode}
    , #{payAmount}
    , #{freightAmt}
    , #{insuranceAmt}
    , #{cargoMgmtNo}
    , #{bondedRepName}
    , #{carrierName}
    , #{vesselName}
    , #{loadingLoc}
    , #{contNo}
    , #{hsCode}
    , #{itemNameDeclared}
    , #{itemNameTrade}
    , #{brandName}
    , #{totalWeight}
    , #{totalPackCnt}
    , #{qty}
    , #{qtyUnit}
    , #{invoiceNo}
    , #{originCountry}
    , #{modelName}
    , #{unitPrice}
    , #{totalDeclAmt}
    , #{status}
    , #{exportNumber}
    , #{dclType}
    , #{transMode}
    , #{exportKind}
    , #{paymentMethod}
    , #{incoterms}
    , #{transportMode}
    , #{containerMode}
    , #{goodsType}
    , #{refundApplicant}
    , #{regDate}
    , #{invoiceSign}
    , #{attachYn}
    , #{originCriteria}
    , #{originMarkYn}
    , #{originCertType}
    , #{submitDate}
)
